import os
import json
import secrets
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from datetime import datetime, timedelta
import requests
from config import (
    APPWRITE_ENDPOINT, APPWRITE_PROJECT_ID, APPWRITE_API_KEY,
    APPWRITE_DATABASE_ID, APPWRITE_USERS_COLLECTION,
    APPWRITE_DOWNLOADS_COLLECTION, SESSION_FILE, SESSION_TIMEOUT_DAYS,
    SMTP_EMAIL, SMTP_PASSWORD, SMTP_HOST, SMTP_PORT, SMTP_FROM_NAME,
    APP_NAME, VERSION, EDITION, BRAND, AUTHOR
)
from utils import logger


class AppwriteAuth:
    def __init__(self):
        self.endpoint = APPWRITE_ENDPOINT
        self.project_id = APPWRITE_PROJECT_ID
        self.api_key = APPWRITE_API_KEY
        self.database_id = APPWRITE_DATABASE_ID

        self.headers = {
            'X-Appwrite-Project': self.project_id,
            'X-Appwrite-Key': self.api_key,
            'Content-Type': 'application/json'
        }

        self.current_user = None
        self.session_data = None
        self.load_local_session()

    def _request(self, method, path, data=None):
        url = f"{self.endpoint}{path}"
        try:
            if method == 'GET':
                response = requests.get(url, headers=self.headers)
            elif method == 'POST':
                response = requests.post(url, headers=self.headers, json=data)
            elif method == 'PUT':
                response = requests.put(url, headers=self.headers, json=data)
            elif method == 'DELETE':
                response = requests.delete(url, headers=self.headers)

            if response.status_code in [200, 201, 204]:
                return True, response.json() if response.text else {}
            else:
                error_msg = response.json().get('message', str(response.status_code))
                return False, error_msg
        except Exception as e:
            return False, str(e)

    def generate_verification_code(self):
        return ''.join([str(secrets.randbelow(10)) for _ in range(6)])

    def send_verification_email(self, to_email, code, full_name=""):
        try:
            year = datetime.now().year
            body = f"""
            <!DOCTYPE html>
            <html lang="en">
            <head><meta charset="UTF-8"><title>Verify Your Email - {APP_NAME}</title></head>
            <body style="margin:0;padding:0;background:#f9f9f9;font-family:'Segoe UI',sans-serif;">
                <div style="max-width:600px;margin:30px auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 6px 30px rgba(0,0,0,0.08);">
                    <div style="background:linear-gradient(135deg,#0b1e33,#152b44);padding:30px;text-align:center;">
                        <h1 style="color:#FFD700;font-size:28px;margin:0;">☀️ {APP_NAME}</h1>
                        <p style="color:rgba(255,255,255,0.8);margin-top:6px;">{BRAND} — Built for Developers</p>
                        <p style="color:#fff;font-size:18px;">🇦🇷 {EDITION} 🇦🇷</p>
                    </div>
                    <div style="padding:35px 30px 25px;">
                        <h2 style="color:#1a2332;">Hello {full_name or 'Valued User'}! 👋</h2>
                        <p style="color:#4a5568;font-size:15px;">Thank you for choosing <strong>{APP_NAME}</strong>. To complete your registration, please verify your email.</p>
                        <div style="background:#f6f8fc;border:2px dashed #b0bec5;border-radius:12px;padding:25px;text-align:center;margin:25px 0;">
                            <p style="color:#6b7a8f;text-transform:uppercase;letter-spacing:2px;font-weight:600;">🔐 Your Verification Code</p>
                            <p style="font-size:46px;font-weight:700;color:#0b1e33;letter-spacing:12px;font-family:'Courier New',monospace;">{code}</p>
                            <p style="color:#8a9aa8;">📋 Copy this code and paste it in your terminal</p>
                            <p style="font-size:12px;color:#8a9aa8;">⏱️ Expires in 10 minutes</p>
                        </div>
                        <div style="background:#fff8e1;border-left:4px solid #ffb300;padding:12px;border-radius:4px;color:#6d5a00;">⚠️ If you didn't request this, ignore this email.</div>
                    </div>
                    <div style="background:#0b1e33;padding:20px 30px;text-align:center;border-top:3px solid #FFD700;">
                        <p style="font-size:18px;font-weight:700;color:#FFD700;"><span style="color:#fff;">Code</span>Sun</p>
                        <p style="color:#cbd5e0;font-size:13px;">Building Tools for Developers 🚀</p>
                        <p style="color:#718096;font-size:11px;">© {year} {BRAND}. All rights reserved.<br>🇦🇷 VAMOS ARGENTINA! 🇦🇷</p>
                    </div>
                </div>
            </body>
            </html>
            """
            msg = MIMEMultipart('related')
            msg['From'] = f"{SMTP_FROM_NAME} <{SMTP_EMAIL}>"
            msg['To'] = to_email
            msg['Subject'] = f"🔐 Verify Your Email - {APP_NAME} v{VERSION}"
            msg_alt = MIMEMultipart('alternative')
            msg.attach(msg_alt)
            msg_alt.attach(MIMEText(body, 'html'))

            logo_path = os.path.join(os.path.dirname(__file__), 'public', 'codesun.png')
            if os.path.exists(logo_path):
                with open(logo_path, 'rb') as f:
                    logo_data = f.read()
                img = MIMEText(logo_data, 'image/png')
                img.add_header('Content-ID', '<logo_image>')
                img.add_header('Content-Disposition', 'inline', filename='codesun.png')
                msg.attach(img)

            with smtplib.SMTP(SMTP_HOST, SMTP_PORT) as server:
                server.starttls()
                server.login(SMTP_EMAIL, SMTP_PASSWORD)
                server.send_message(msg)

            logger.info(f"Verification email sent to {to_email}")
            return True, "Verification email sent successfully"
        except Exception as e:
            logger.error(f"Failed to send email: {e}")
            return False, str(e)

    def load_local_session(self):
        if os.path.exists(SESSION_FILE):
            try:
                with open(SESSION_FILE, 'r') as f:
                    self.session_data = json.load(f)
                    if self.session_data:
                        created_at = datetime.fromisoformat(self.session_data.get('created_at', ''))
                        if (datetime.now() - created_at).days >= SESSION_TIMEOUT_DAYS:
                            self.clear_session()
                            return
                        self.current_user = self.session_data.get('user')
            except:
                self.session_data = None
                self.current_user = None

    def save_local_session(self, user_data, session_id=None):
        self.session_data = {
            'user': user_data,
            'session_id': session_id,
            'created_at': datetime.now().isoformat()
        }
        self.current_user = user_data
        try:
            os.makedirs(os.path.dirname(SESSION_FILE), exist_ok=True)
            with open(SESSION_FILE, 'w') as f:
                json.dump(self.session_data, f, indent=2)
        except Exception as e:
            logger.error(f"Failed to save session: {e}")

    def clear_session(self):
        self.session_data = None
        self.current_user = None
        if os.path.exists(SESSION_FILE):
            os.remove(SESSION_FILE)

    def is_authenticated(self):
        if not self.current_user:
            return False
        if self.session_data:
            created_at = datetime.fromisoformat(self.session_data.get('created_at', ''))
            if (datetime.now() - created_at).days >= SESSION_TIMEOUT_DAYS:
                self.clear_session()
                return False
        return True

    def get_current_user(self):
        return self.current_user

    def logout(self):
        try:
            if self.session_data and self.session_data.get('session_id'):
                self._request('DELETE', f"/account/sessions/{self.session_data['session_id']}")
        except:
            pass
        self.clear_session()
        logger.info("User logged out successfully")
        return True, "Logged out successfully"

    def check_username_exists(self, username):
        try:
            success, result = self._request(
                'GET',
                f'/databases/{self.database_id}/collections/{APPWRITE_USERS_COLLECTION}/documents?queries=[username="{username}"]'
            )
            if success:
                return len(result.get('documents', [])) > 0
            return False
        except:
            return False

    def check_email_exists(self, email):
        try:
            success, result = self._request('GET', '/users')
            if success:
                for user in result.get('users', []):
                    if user.get('email') == email:
                        return True
            return False
        except:
            return False

    def get_user_by_username_or_email(self, username_or_email):
        try:
            success, result = self._request(
                'GET',
                f'/databases/{self.database_id}/collections/{APPWRITE_USERS_COLLECTION}/documents?queries=[username="{username_or_email}"]'
            )
            if success and len(result.get('documents', [])) > 0:
                user_doc = result['documents'][0]
                user_id = user_doc.get('userId')
                success, user = self._request('GET', f'/users/{user_id}')
                if success:
                    return user
            success, result = self._request('GET', '/users')
            if success:
                for user in result.get('users', []):
                    if user.get('email') == username_or_email:
                        return user
            return None
        except:
            return None

    def signup(self, full_name, email, username, password):
        if self.check_username_exists(username):
            return False, "Username already exists"
        if self.check_email_exists(email):
            return False, "Email already registered"

        user_id = secrets.token_hex(16)
        user_data = {
            'userId': user_id,
            'email': email,
            'password': password,
            'name': full_name
        }
        success, resp = self._request('POST', '/users', user_data)
        if not success:
            return False, f"User creation failed: {resp}"

        doc_data = {
            'documentId': user_id,
            'data': {
                'userId': user_id,
                'username': username,
                'fullName': full_name,
                'email': email,
                'verified': False,
                'createdAt': datetime.now().isoformat()
            }
        }
        self._request(
            'POST',
            f'/databases/{self.database_id}/collections/{APPWRITE_USERS_COLLECTION}/documents',
            doc_data
        )

        user_info = {
            'id': user_id,
            'name': full_name,
            'email': email,
            'username': username
        }
        self.save_local_session(user_info)
        return True, "Account created successfully"

    def login(self, username_or_email, password):
        user = self.get_user_by_username_or_email(username_or_email)
        if not user:
            return False, "User not found"

        session_data = {
            'email': user['email'],
            'password': password
        }
        success, resp = self._request('POST', '/account/sessions/email', session_data)
        if not success:
            return False, "Invalid credentials"

        user_id = user['$id']
        user_info = {
            'id': user_id,
            'email': user['email'],
            'name': user.get('name', ''),
            'username': username_or_email
        }

        success, docs = self._request(
            'GET',
            f'/databases/{self.database_id}/collections/{APPWRITE_USERS_COLLECTION}/documents?queries=[userId="{user_id}"]'
        )
        if success and docs.get('documents'):
            user_info['username'] = docs['documents'][0]['data'].get('username', username_or_email)

        self.save_local_session(user_info, resp.get('$id'))
        return True, "Login successful"


auth = AppwriteAuth()
